 22	/*! \file pdcp_sequence_manager.c
 23	* \brief PDCP Sequence Numbering Methods
 24	* \author Baris Demiray and Navid Nikaein
 25	* \email navid.nikaein@eurecom.fr
 26	* \date 2014
 27	*/
 28	
 29	#include "pdcp_sequence_manager.h"
 30	#include "common/utils/LOG/log.h"
 31	#include "pdcp_util.h"
 32	
 33	/*
 34	 * Initializes sequence numbering state
 35	 * @param pdcp_entity The PDCP entity to be initialized
 36	 * @return bool true on success, false otherwise
 37	 */
 38	bool pdcp_init_seq_numbers(pdcp_t* pdcp_entity)
 39	{
 40	  if (pdcp_entity == NULL) {
 41	    return false;
 42	  }
 43	
 44	  /* Sequence number state variables */
 45	
 46	  // TX and RX window
 47	  pdcp_entity->next_pdcp_tx_sn = 0;
 48	  pdcp_entity->next_pdcp_rx_sn = 0;
 49	
 50	  // TX and RX Hyper Frame Numbers
 51	  pdcp_entity->tx_hfn = 0;
 52	  pdcp_entity->rx_hfn = 0;
 53	
 54	  // SN of the last PDCP SDU delivered to upper layers
 55	  // Shall UE and eNB behave differently on initialization? (see 7.1.e)
 56	  pdcp_entity->last_submitted_pdcp_rx_sn = 4095;
 57	
 58	  return true;
 59	}
 60	
 61	bool pdcp_is_seq_num_size_valid(pdcp_t* pdcp_entity)
 62	{
 63	  if (pdcp_entity == NULL) {
 64	    return false;
 65	  }
 66	
 67	  // Check if the size of SN is valid (see 3GPP TS 36.323 v10.1.0 item 6.3.2)
 68	  if (pdcp_entity->seq_num_size != 5 && pdcp_entity->seq_num_size != 7 && pdcp_entity->seq_num_size != 12) {
 69	    LOG_W(PDCP, "Incoming SN size is invalid! (Expected: {5 | 7 | 12}, Received: %d\n", pdcp_entity->seq_num_size);
 70	    return false;
 71	  }
 72	
 73	  return true;
 74	}
 75	
 76	/**
 77	 * Check if SN number is in the range according to SN size
 78	 */
 79	bool pdcp_is_seq_num_valid(uint16_t seq_num, uint8_t seq_num_size)
 80	{
 81	  if (seq_num >= 0 && seq_num <= pdcp_calculate_max_seq_num_for_given_size(seq_num_size)) {
 82	    return true;
 83	  }
 84	
 85	  return false;
 86	}
 87	
 88	uint16_t pdcp_calculate_max_seq_num_for_given_size(uint8_t seq_num_size)
 89	{
 90	  uint16_t max_seq_num = 1;
 91	
 92	  max_seq_num <<= seq_num_size;
 93	
 94	  return max_seq_num - 1;
 95	}
 96	
 97	uint16_t pdcp_get_next_tx_seq_number(pdcp_t* pdcp_entity)
 98	{
 99	  if (pdcp_is_seq_num_size_valid(pdcp_entity) == false) {
100	    return -1;
101	  }
102	
103	  // Sequence number should be incremented after it is assigned for a PDU
104	  uint16_t pdcp_seq_num = pdcp_entity->next_pdcp_tx_sn;
105	
106	  /*
107	   * Update sequence numbering state and Hyper Frame Number if SN has already reached
108	   * its max value (see 5.1 PDCP Data Transfer Procedures)
109	   */
110	  if (pdcp_entity->next_pdcp_tx_sn == pdcp_calculate_max_seq_num_for_given_size(pdcp_entity->seq_num_size)) {
111	    pdcp_entity->next_pdcp_tx_sn = 0;
112	    pdcp_entity->tx_hfn++;
113	    LOG_D(PDCP,"Reseting the PDCP sequence number\n");
114	  } else {
115	    pdcp_entity->next_pdcp_tx_sn++;
116	  }
117	
118	  return pdcp_seq_num;
119	}
120	
121	bool pdcp_advance_rx_window(pdcp_t* pdcp_entity)
122	{
123	  if (pdcp_is_seq_num_size_valid(pdcp_entity) == false) {
124	    return false;
125	  }
126	
127	  /*
128	   * Update sequence numbering state and Hyper Frame Number if SN has already reached
129	   * its max value (see 5.1 PDCP Data Transfer Procedures)
130	   */
131	  LOG_D(PDCP, "Advancing RX window...\n");
132	
133	  if (pdcp_entity->next_pdcp_rx_sn == pdcp_calculate_max_seq_num_for_given_size(pdcp_entity->seq_num_size)) {
134	    pdcp_entity->next_pdcp_rx_sn = 0;
135	    pdcp_entity->rx_hfn++;
136	  } else {
137	    pdcp_entity->next_pdcp_rx_sn++;
138	  }
139	
140	  return true;
141	}
142	
143	bool pdcp_mark_current_pdu_as_received(uint16_t seq_num, pdcp_t* pdcp_entity)
144	{
145	  /*
146	   * Incoming sequence number and PDCP entity were already
147	   * validated in pdcp_is_rx_seq_number_valid() so we don't
148	   * check here
149	   */
150	
151	  /*
152	   * Find relevant octet
153	   */
154	  uint16_t octet_index = seq_num / 8;
155	  /*
156	   * Set relevant bit
157	   */
158	  LOG_D(PDCP, "Marking %d. bit of %d. octet of status bitmap\n", (seq_num % 8) + 1, octet_index);
159	  util_mark_nth_bit_of_octet(&pdcp_entity->missing_pdu_bitmap[octet_index], seq_num % 8);
160	  util_print_binary_representation((uint8_t*)"Current state of relevant octet: ", pdcp_entity->missing_pdu_bitmap[octet_index]);
161	  return true;
162	}

bool pdcp_advance_rx_window(pdcp_t* pdcp_entity)
{
  if (pdcp_is_seq_num_size_valid(pdcp_entity) == false) {
    return false;
  }

  /*
   * Update sequence numbering state and Hyper Frame Number if SN has already reached
   * its max value (see 5.1 PDCP Data Transfer Procedures)
   */
  LOG_D(PDCP, "Advancing RX window...\n");

  if (pdcp_entity->next_pdcp_rx_sn == pdcp_calculate_max_seq_num_for_given_size(pdcp_entity->seq_num_size)) {
    pdcp_entity->next_pdcp_rx_sn = 0;
    pdcp_entity->rx_hfn++;
  } else {
    pdcp_entity->next_pdcp_rx_sn++;
  }

  return true;
}

